import axios from 'axios';

/**
 * API origin. Set in project root .env:
 *   REACT_APP_API_BASE_URL=http://localhost:5000
 * Production: use your public backend URL. Vercel "Deployment Protection" on the API
 * blocks browsers (401 HTML) — disable it for the API or use an unprotected production URL.
 */
function resolveApiBaseUrl() {
  const raw = (process.env.REACT_APP_API_BASE_URL || "").trim().replace(/\/$/, "");
  if (raw) return raw;
  if (process.env.NODE_ENV === "development") return "http://localhost:5000";
  return "";
}

export const API_BASE_URL = resolveApiBaseUrl();

if (!API_BASE_URL && process.env.NODE_ENV === "production") {
  // eslint-disable-next-line no-console
  console.error(
    "[badee] REACT_APP_API_BASE_URL is missing. Set it before `npm run build` so the app can reach your backend.",
  );
}

const api = axios.create({
  baseURL: API_BASE_URL,
  // NO default Content-Type — set per-request in interceptor
});

api.interceptors.request.use((config) => {
  // Attach token
  const token = localStorage.getItem('jt_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;

  // Set Content-Type only for non-FormData requests
  if (config.data instanceof FormData) {
    // DELETE the header entirely so axios auto-sets:
    // "multipart/form-data; boundary=----WebKitXYZ"
    // Any manual value here would strip the boundary and break multer
    delete config.headers['Content-Type'];
    delete config.headers['content-type'];
    if (config.headers.common) {
      delete config.headers.common['Content-Type'];
    }
  } else {
    config.headers['Content-Type'] = 'application/json';
  }

  return config;
});

api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('jt_token');
      localStorage.removeItem('jt_user');
    }
    return Promise.reject(err);
  }
);

export default api;
